- D: [Reverse Conditional] No evidence of concealed data appears in the text.', NULL, 'Information and Ideas', 'Inferences', 'reading_writing', 'information', 'INF', 'INF', 'easy'::public.difficulty, false, 'SAT', 'multiple_choice'::public.question_type, false, true, 'exam_simulator', '{"exam_simulator_v1":true,"simulator_form":1,"module_key":"rw_module_1","slot":7,"filter_section":"reading_writing","module_index":1,"m2_variant":null,"form_hardness":1,"difficulty_band":"easy"}'::jsonb, now(), now())
