- D: [Reverse Conditional] No pricing information appears.', NULL, 'Information and Ideas', 'Inferences', 'reading_writing', 'information', 'INF', 'INF', 'hard'::public.difficulty, false, 'SAT', 'multiple_choice'::public.question_type, false, true, 'exam_simulator', '{"exam_simulator_v1":true,"simulator_form":2,"module_key":"rw_module_2_hard","slot":21,"filter_section":"reading_writing","module_index":2,"m2_variant":"hard","form_hardness":2,"difficulty_band":"hard"}'::jsonb, now(), now())
