- C: [Flat Literal] "to ignore" contradicts the sentence logic requiring a provisional judgment.
- D: [Tone Inversion] "to multiply" contradicts the sentence logic requiring a provisional judgment.', NULL, 'Craft and Structure', 'Words in Context', 'reading_writing', 'craft', 'WIC', 'WIC', 'easy'::public.difficulty, false, 'SAT', 'multiple_choice'::public.question_type, false, true, 'exam_simulator', '{"exam_simulator_v1":true,"simulator_form":3,"module_key":"rw_module_2_hard","slot":0,"filter_section":"reading_writing","module_index":2,"m2_variant":"hard","form_hardness":3,"difficulty_band":"easy"}'::jsonb, now(), now())
