INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('09fc08a0-f296-4783-a6af-7ad24359ebd1', 'Which choice completes the text with the most logical transition?', 'Historians examining trade route 5229954 note that camel caravans carried not only goods but also astronomical tables, spreading navigation techniques across deserts long before printed maps existed. Merchants who survived the crossing depended on star charts copied onto leather scrolls, and those copies often accumulated marginal notes from later travelers. A ledger recovered near route 5229954 lists dates, caravan leaders, and the scientific texts exchanged at each oasis, suggesting that commerce and scholarship moved together. When one city tightened tariffs, caravans rerouted through secondary wells, and the astronomical knowledge rerouted with them. Modern scholars therefore treat desert trade networks as early information highways rather than simple supply chains. The passage emphasizes how practical navigation needs drove the circulation of technical knowledge among communities that rarely shared a written language. Recent digitization projects have linked surviving ledger fragments to star-chart marginalia, strengthening the case for integrated commercial and intellectual exchange. The ______ the subsequent section extends the author''s nuanced argument.', 'passage', '[{"id":"A","text":"Complicating the binary the author has established in the opening paragraphs,","is_correct":true,"explanation":"Correct (A). Complicating the binary the author has established in the opening paragraphs, This participial phrase signals contrast while preserving sentence grammar, matching Digital SAT hard transition expectations."},{"id":"B","text":"Undermining the neat separation outlined above between cause and effect,","is_correct":false,"explanation":"[Synonym Trap] Undermining the neat separation outlined above between cause and effect, This phrase suggests a different rhetorical relationship than the one required between the two clauses."},{"id":"C","text":"Extending the causal chain the author has begun to trace across the study,","is_correct":false,"explanation":"[Category Shift] Extending the causal chain the author has begun to trace across the study, This phrase suggests a different rhetorical relationship than the one required between the two clauses."},{"id":"D","text":"Reinforcing the cumulative case the passage has assembled through converging evidence,","is_correct":false,"explanation":"[Register Clash] Reinforcing the cumulative case the passage has assembled through converging evidence, This phrase suggests a different rhetorical relationship than the one required between the two clauses."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
Focus on {{yellow:caravan}} in the passage. The transition item asks you to identify the relationship before comparing choices.

Step 2 — Test transition logic
Compare each option against explicit textual evidence. On hard items, correct answers usually restate the passage faithfully without absolute words the text does not support.

Step 3 — Complete the sentence
Choice A is correct: Complicating the binary the author has established in the opening paragraphs,.

Distractor analysis:
- B: [Synonym Trap] Undermining the neat separation outlined above between cause and effect, This phrase suggests a different rhetorical relationship than the one required between the two clauses.
- C: [Category Shift] Extending the causal chain the author has begun to trace across the study, This phrase suggests a different rhetorical relationship than the one required between the two clauses.
- D: [Register Clash] Reinforcing the cumulative case the passage has assembled through converging evidence, This phrase suggests a different rhetorical relationship than the one required between the two clauses.', NULL, 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', 'TRA', 'hard'::public.difficulty, false, 'SAT', 'multiple_choice'::public.question_type, false, true, 'exam_simulator', '{"exam_simulator_v1":true,"simulator_form":3,"module_key":"rw_module_2_hard","slot":22,"filter_section":"reading_writing","module_index":2,"m2_variant":"hard","form_hardness":3,"difficulty_band":"hard"}'::jsonb, now(), now())
