- D: [True-But-Irrelevant] Both passage and table must be used together.', NULL, 'Information and Ideas', 'Command of Evidence', 'reading_writing', 'information', 'COE', 'COE', 'easy'::public.difficulty, false, 'SAT', 'multiple_choice'::public.question_type, false, true, 'exam_simulator', '{"exam_simulator_v1":true,"simulator_form":4,"module_key":"rw_module_2_easy","slot":5,"filter_section":"reading_writing","module_index":2,"m2_variant":"easy","form_hardness":4,"difficulty_band":"easy"}'::jsonb, now(), now())
