- D: [Reverse Conditional] No pricing information appears.', NULL, 'Information and Ideas', 'Inferences', 'reading_writing', 'information', 'INF', 'INF', 'hard'::public.difficulty, false, 'SAT', 'multiple_choice'::public.question_type, false, true, 'exam_simulator', '{"exam_simulator_v1":true,"simulator_form":6,"module_key":"rw_module_1","slot":21,"filter_section":"reading_writing","module_index":1,"m2_variant":null,"form_hardness":6,"difficulty_band":"hard"}'::jsonb, now(), now())
