INSERT INTO public.questions
(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('19a3b781-8460-458c-a12c-c7df0c6a9fd8', 'Which choice completes the text with the most logical transition?', 'Economists analyzing market 5914116 observed that small retailers adapted faster than national chains when supply chains stalled, partly because they could reorder from local wholesalers within days. While big-box stores waited for centralized distribution centers to reopen, corner shops phoned alternate suppliers named in handwritten contact lists. The economists interviewed owners who shifted product mix toward shelf-stable goods and services that did not depend on overseas shipping. National chains, bound to national contracts and uniform pricing algorithms, could not pivot as quickly without corporate approval cycles. The study does not claim small stores always outperform chains; rather, it shows that flexibility and local relationships became decisive when long-distance logistics failed. Readers should infer that organizational scale can become a liability during sudden disruptions. A follow-up survey eighteen months later found that retailers who diversified suppliers during the stall retained higher customer loyalty scores. The authors stress that replication across independent ______ the subsequent section extends the author''s nuanced argument.', 'passage', '[{"id":"A","text":"Qualifying the sweeping claim made in the prior sentence with added nuance,","is_correct":true,"explanation":"Correct (A). Qualifying the sweeping claim made in the prior sentence with added nuance, This participial phrase signals contrast while preserving sentence grammar, matching Digital SAT hard transition expectations."},{"id":"B","text":"Reinforcing the cumulative case the passage has assembled through converging evidence,","is_correct":false,"explanation":"[Synonym Trap] Reinforcing the cumulative case the passage has assembled through converging evidence, This phrase suggests a different rhetorical relationship than the one required between the two clauses."},{"id":"C","text":"Grounding the general statement in a specific instance the researchers documented,","is_correct":false,"explanation":"[Category Shift] Grounding the general statement in a specific instance the researchers documented, This phrase suggests a different rhetorical relationship than the one required between the two clauses."},{"id":"D","text":"Undermining the neat separation outlined above between cause and effect,","is_correct":false,"explanation":"[Register Clash] Undermining the neat separation outlined above between cause and effect, This phrase suggests a different rhetorical relationship than the one required between the two clauses."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
Focus on {{yellow:product}} in the passage. The transition item asks you to identify the relationship before comparing choices.

Step 2 — Test transition logic
Compare each option against explicit textual evidence. On hard items, correct answers usually restate the passage faithfully without absolute words the text does not support.

Step 3 — Complete the sentence
Choice A is correct: Qualifying the sweeping claim made in the prior sentence with added nuance,.

Distractor analysis:
- B: [Synonym Trap] Reinforcing the cumulative case the passage has assembled through converging evidence, This phrase suggests a different rhetorical relationship than the one required between the two clauses.
- C: [Category Shift] Grounding the general statement in a specific instance the researchers documented, This phrase suggests a different rhetorical relationship than the one required between the two clauses.
- D: [Register Clash] Undermining the neat separation outlined above between cause and effect, This phrase suggests a different rhetorical relationship than the one required between the two clauses.', NULL, 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', 'TRA', 'hard'::public.difficulty, false, 'SAT', 'multiple_choice'::public.question_type, false, true, 'exam_simulator', '{"exam_simulator_v1":true,"simulator_form":10,"module_key":"rw_module_1","slot":22,"filter_section":"reading_writing","module_index":1,"m2_variant":null,"form_hardness":10,"difficulty_band":"hard"}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
