(id, question_text, stimulus_text, stimulus_type, options, correct_answer, explanation, hint, topic, subtopic, section, domain_id, skill_id, math_skill_code, difficulty, calculator_allowed, exam_type, question_type, is_platform_question, ai_generated, source, source_metadata, created_at, updated_at)
VALUES ('73c13161-19c8-408a-bbaa-971e6b6ac117', 'Which choice completes the text with the most logical transition?', 'In her essay on urban soundscapes, writer 5922035 argues that city planners should treat noise pollution as a public-health issue, citing studies linking traffic noise to elevated stress hormones. She describes neighborhoods where sirens, construction, and highway hum overlap for eighteen hours a day, leaving residents with fragmented sleep even when air quality meets regulatory standards. Community interviews quoted in the essay repeatedly mention difficulty concentrating at work and heightened irritability at home. The writer contrasts cosmetic beautification projects—new planters and paint—with measurable acoustic interventions such as berms, low-noise pavement, and delivery-time restrictions. She acknowledges that complete silence is impossible in dense cities, yet insists that reducing predictable high-decibel spikes could yield health benefits comparable to modest improvements in green space. The essay concludes that sound belongs in urban planning budgets alongside light and air. Pilot programs in three cities reported measurable sleep gains after targeted speed reductions on arterial ______ the subsequent section extends the author''s nuanced argument.', 'passage', '[{"id":"A","text":"Undermining the neat separation outlined above between cause and effect,","is_correct":true,"explanation":"Correct (A). Undermining the neat separation outlined above between cause and effect, This participial phrase signals contrast while preserving sentence grammar, matching Digital SAT hard transition expectations."},{"id":"B","text":"Extending the author''s line of reasoning further into the policy implications,","is_correct":false,"explanation":"[Synonym Trap] Extending the author''s line of reasoning further into the policy implications, This phrase suggests a different rhetorical relationship than the one required between the two clauses."},{"id":"C","text":"Illustrating the abstract claim with a concrete case drawn from the data,","is_correct":false,"explanation":"[Category Shift] Illustrating the abstract claim with a concrete case drawn from the data, This phrase suggests a different rhetorical relationship than the one required between the two clauses."},{"id":"D","text":"Complicating the binary the author has established in the opening paragraphs,","is_correct":false,"explanation":"[Register Clash] Complicating the binary the author has established in the opening paragraphs, This phrase suggests a different rhetorical relationship than the one required between the two clauses."}]'::jsonb, 'A', 'Step 1 — Identify the relationship
Focus on {{yellow:interviews}} in the passage. The transition item asks you to identify the relationship before comparing choices.

Step 2 — Test transition logic
Compare each option against explicit textual evidence. On hard items, correct answers usually restate the passage faithfully without absolute words the text does not support.

Step 3 — Complete the sentence
Choice A is correct: Undermining the neat separation outlined above between cause and effect,.

Distractor analysis:
- B: [Synonym Trap] Extending the author''s line of reasoning further into the policy implications, This phrase suggests a different rhetorical relationship than the one required between the two clauses.
- C: [Category Shift] Illustrating the abstract claim with a concrete case drawn from the data, This phrase suggests a different rhetorical relationship than the one required between the two clauses.
- D: [Register Clash] Complicating the binary the author has established in the opening paragraphs, This phrase suggests a different rhetorical relationship than the one required between the two clauses.', NULL, 'Expression of Ideas', 'Transitions', 'reading_writing', 'expression', 'TRA', 'TRA', 'hard'::public.difficulty, false, 'SAT', 'multiple_choice'::public.question_type, false, true, 'exam_simulator', '{"exam_simulator_v1":true,"simulator_form":10,"module_key":"rw_module_2_easy","slot":22,"filter_section":"reading_writing","module_index":2,"m2_variant":"easy","form_hardness":10,"difficulty_band":"hard"}'::jsonb, now(), now())
ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions
